#!/usr/bin/env bash
# runway-decay-risk-high-last-upda.sh — 图生视频 / 文生视频（可灵 / 即梦 / Runway）(Decay risk: high) last_updated: 2026-06-22 SOP walkthrough for AIGC 创作工作流.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AIGC 创作工作流"
WORKFLOW="图生视频 / 文生视频（可灵 / 即梦 / Runway）(Decay risk: high) last_updated: 2026-06-22"

usage() {
  cat <<EOF
runway-decay-risk-high-last-upda.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./runway-decay-risk-high-last-upda.sh             # interactive
  ./runway-decay-risk-high-last-upda.sh --dry-run
  ./runway-decay-risk-high-last-upda.sh --json
  ./runway-decay-risk-high-last-upda.sh --explain
  ./runway-decay-risk-high-last-upda.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "图生视频 / 文生视频（可灵 / 即梦 / Runway）(Decay risk: high) last_updated: 2026-06-22" 工作流。

一句话: 把静帧变成有运镜、有时长、可控动态的视频 clip —— 先出高质量首帧→图生视频设运镜/时长/首尾帧/动态强度→多 clip 锁一致→可选对口型配音→剪辑合成。从「一张图」到「一个会动的镜头」。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • 可控性 ⇄ 抽卡随机（slot machine）的第一性张力: 扩散模型本质是「抽卡机」（Bilawal Sidhu 直接命名 slot machine nature），同 prompt 多跑挑可用——生成式视觉创作的每个决策都在「可控性/工程化复现 ⇄ 随机性/
  • 模型是地板，审美与判断是天花板: 同样的模型与参数，产出天差地别取决于人的审美判断、概念、构图、镜头语言与「在哪一步停」的判断；模型决定下限（地板），人的审美与工程判断决定上限（天花板），「换个更大的底模就行」是外行幻觉。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**出高质量首帧**：先用图像工作流（workflow 1）出一张满意的首帧（视频质量上限基本由首帧决定）。"
  "**选模型上传首帧**：Kling（性价比/中文）/ 即梦 Seedance（多模态参考）/ Runway（精细运镜）/ Veo（原生音频），上传首帧进 image-to-video。"
  "**写运动+运镜 prompt**：I2V 模式只描述「动作 + 运镜」，不重复描述画面（模型已看到首帧）。运镜用内置 token（push/pull/pan/tilt/orbit/zoom）。(evidence: [T03-S016])"
  "**设动态强度/时长**：选 Subtle/Moderate/Dynamic 动态档，设时长。"
  "**首尾帧控制（如需）**：上传 start/end 帧让模型插值过渡（适合 before/after、可控转场）；Kling Video 3.0 官方支持首尾帧、运动笔刷（给图上指定区域刷方向矢量控运动）。(evidence: [T03-S016, T03-S023])"
  "**抽卡筛 + 重生**：视频仍是抽卡，跑几版挑动态自然、无崩坏的。"
)
declare -a FAILURE_MODES=(
  "**首帧不行就硬 I2V**：低质首帧的瑕疵在视频里被放大成动态崩坏 —— 先把首帧打磨到交付级再进 I2V。"
  "**运镜靠堆 prompt 而非内置控制**：文字描述运镜不可控、每次不同 —— 用模型内置运镜 token（push/orbit/zoom）+ 动态强度档。"
  "**单押一家闭源视频模型**：Sora 即将下线、代际半年一跳 —— 关键管线留开源（Wan/Hunyuan）或多供应商退路。"
  "**动态强度与内容错配**：人像/产品用 Dynamic 档变鬼畜 —— 静物/人像用 Subtle，动作戏才用 Dynamic。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "runway-decay-risk-high-last-upda-walkthrough"
fi
